        function streamStart() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
            var deviceId = window.connectedDevice.ip;
            var device = allDevices.find(function(d) { return d.ip === deviceId; });
            document.getElementById('btnStreamStart').disabled = true;
            document.getElementById('streamStatusInfo').textContent = '状态: 正在启动...';
            var url = '/api/v1/streams/' + deviceId + '/start';
